# Module defining entity classes
from types_module import IIdentifiable, INamed, Status, Point

class Entity(IIdentifiable, INamed):
    _id: int
    _name: str
    status: Status

    def __init__(self, entity_id: int, name: str):
        self._id = entity_id
        self._name = name
        self.status = Status.PENDING

    @override
    def get_id(self) -> int:
        return self._id

    @override
    def get_name(self) -> str:
        return self._name

    def get_position(self) -> Point:
        return Point(0.0, 0.0)

class Creature(Entity):
    hit_points: int

    def __init__(self, entity_id: int, name: str, hp: int):
        super().__init__(entity_id, name)
        self.hit_points = hp

