# Module providing utility functions
from types_module import Status

class Processor:
    call_count: int

    def __init__(self):
        self.call_count = 0

    def process(self, n: int) -> int:
        self.call_count += 1
        return n * 2

    def get_status(self) -> Status:
        return Status.ACTIVE

def is_positive(n: int) -> bool:
    return n > 0

def compute_result(x: int, y: int) -> int:
    return x + y * 2

def apply_predicate(pred: (int) -> bool, n: int) -> bool:
    return pred(n)
